module up_down_counter(reset, RST, UP, DOWN, COUNT);
input reset, RST, UP, DOWN;
output [3:0] COUNT;
reg [3:0] COUNT;

always @(posedge reset or posedge RST) begin
    if (RST)
        COUNT <= 0;
    else if (UP)
        COUNT <= COUNT + 1;
    else if (DOWN)
        COUNT <= COUNT - 1;
end

endmodule
